// N8N Function Node — Formatar erro p/ Telegram com timezone correto
const data = $input.all();

const TZ = 'America/Sao_Paulo';
const TELEGRAM_LIMIT = 4096;
const SAFE_LIMIT = 3500; // margem de segurança
const ERROR_LIMIT = 150; // limite só para o bloco do erro

const fmt = (iso) =>
  new Intl.DateTimeFormat('pt-BR', {
    timeZone: TZ,
    dateStyle: 'short',
    timeStyle: 'medium',
  }).format(new Date(iso));

function truncateText(text, maxLen, suffix = '[..." (truncated)]') {
  if (!text) return '';
  const str = String(text);
  if (str.length <= maxLen) return str;
  return str.slice(0, maxLen - suffix.length) + suffix;
}

function formatErrorForTelegram(item) {
  const e = item.json?.execution || {};
  const w = item.json?.workflow || {};

  const occurredAtISO =
    e.stoppedAt || e.finishedAt || e.startedAt || new Date().toISOString();

  const rawError =
    e.error?.message ||
    e.error?.description ||
    JSON.stringify(e.error || {}, null, 2) ||
    'Unknown error';

  const errMsg = truncateText(rawError, ERROR_LIMIT);

  let msg = '';
  msg += `🚨 *ERROR IN AUTOMATION* 🚨 `;
  msg += `${fmt(occurredAtISO)}\n\n`;

  msg += `📋 *Workflow:* ${w.name || 'N/A'}\n`;
  msg += `🆔 *ID:* ${w.id || 'N/A'}\n\n`;
  msg += `⚡ *Execution:* #${e.id || 'N/A'}\n`;
  msg += `🔄 *Mode:* ${e.mode || 'N/A'}\n`;
  if (e.retryOf) msg += `🔁 *Retry of:* #${e.retryOf}\n`;
  if (e.lastNodeExecuted) msg += `📍 *Last node:* ${e.lastNodeExecuted}\n`;
  msg += `\n`;

  msg += `❌ *Error:*\n${errMsg}\n\n`;

  if (e.url) msg += `🔗 *See details:*\n${e.url}\n\n`;

  // trava final de segurança no texto inteiro
  msg = truncateText(msg, SAFE_LIMIT);

  return {
    json: {
      telegram_message: msg,
      error_summary: {
        workflow_name: w.name,
        execution_id: e.id,
        error_message: errMsg,
        failed_node: e.lastNodeExecuted || null,
        occurred_at_iso: occurredAtISO,
        occurred_at_br: fmt(occurredAtISO),
        was_truncated: rawError.length > ERROR_LIMIT,
        original_error_length: String(rawError).length,
        final_message_length: msg.length,
      },
    },
  };
}

return data.map(formatErrorForTelegram);
